"use strict";(globalThis.webpackChunk_workloom_website=globalThis.webpackChunk_workloom_website||[]).push([[218],{5135(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"current","label":"Next","banner":null,"badge":false,"noIndex":false,"className":"docs-version-current","isLast":true,"docsSidebars":{"docs":[{"type":"link","label":"Introduction","href":"/workloom-releases/docs/intro","docId":"intro","unlisted":false},{"type":"category","label":"Getting Started","collapsed":false,"items":[{"type":"link","label":"Installation","href":"/workloom-releases/docs/getting-started/installation","docId":"getting-started/installation","unlisted":false},{"type":"link","label":"Quick Start","href":"/workloom-releases/docs/getting-started/quick-start","docId":"getting-started/quick-start","unlisted":false},{"type":"link","label":"Your First Workspace","href":"/workloom-releases/docs/getting-started/first-workspace","docId":"getting-started/first-workspace","unlisted":false}],"collapsible":true},{"type":"category","label":"Core Concepts","items":[{"type":"link","label":"Packages & Assets","href":"/workloom-releases/docs/concepts/packages-and-assets","docId":"concepts/packages-and-assets","unlisted":false},{"type":"link","label":"Workspaces & Targets","href":"/workloom-releases/docs/concepts/workspaces-and-targets","docId":"concepts/workspaces-and-targets","unlisted":false},{"type":"link","label":"Providers","href":"/workloom-releases/docs/concepts/providers","docId":"concepts/providers","unlisted":false},{"type":"link","label":"Trust & Privacy","href":"/workloom-releases/docs/concepts/trust-and-privacy","docId":"concepts/trust-and-privacy","unlisted":false},{"type":"link","label":"Drift Detection","href":"/workloom-releases/docs/concepts/drift-detection","docId":"concepts/drift-detection","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Guides","items":[{"type":"link","label":"Setting Up Claude","href":"/workloom-releases/docs/guides/claude-setup","docId":"guides/claude-setup","unlisted":false},{"type":"link","label":"Setting Up Codex","href":"/workloom-releases/docs/guides/codex-setup","docId":"guides/codex-setup","unlisted":false},{"type":"link","label":"Monorepo Configuration","href":"/workloom-releases/docs/guides/monorepo","docId":"guides/monorepo","unlisted":false},{"type":"link","label":"CI/CD Integration","href":"/workloom-releases/docs/guides/ci-cd","docId":"guides/ci-cd","unlisted":false},{"type":"link","label":"Role Providers","href":"/workloom-releases/docs/guides/role-providers","docId":"guides/role-providers","unlisted":false},{"type":"link","label":"Environment Configuration","href":"/workloom-releases/docs/guides/environment-config","docId":"guides/environment-config","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Architecture","items":[{"type":"link","label":"System Overview","href":"/workloom-releases/docs/architecture/overview","docId":"architecture/overview","unlisted":false},{"type":"link","label":"Rendering Pipeline","href":"/workloom-releases/docs/architecture/rendering-pipeline","docId":"architecture/rendering-pipeline","unlisted":false},{"type":"link","label":"API Server & Code Generation","href":"/workloom-releases/docs/architecture/api-server","docId":"architecture/api-server","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"CLI Reference","items":[{"type":"link","label":"wl validate","href":"/workloom-releases/docs/cli/validate","docId":"cli/validate","unlisted":false},{"type":"link","label":"wl init","href":"/workloom-releases/docs/cli/init","docId":"cli/init","unlisted":false},{"type":"link","label":"wl pull","href":"/workloom-releases/docs/cli/pull","docId":"cli/pull","unlisted":false},{"type":"link","label":"wl sync","href":"/workloom-releases/docs/cli/sync","docId":"cli/sync","unlisted":false},{"type":"link","label":"wl status","href":"/workloom-releases/docs/cli/status","docId":"cli/status","unlisted":false},{"type":"link","label":"wl diff","href":"/workloom-releases/docs/cli/diff","docId":"cli/diff","unlisted":false},{"type":"link","label":"wl restore","href":"/workloom-releases/docs/cli/restore","docId":"cli/restore","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"link","label":"Contributing","href":"/workloom-releases/docs/contributing","docId":"contributing","unlisted":false}]},"docs":{"architecture/api-server":{"id":"architecture/api-server","title":"API Server & Code Generation","description":"Workloom\'s backend is a standalone Hono API server with OpenAPI documentation generated from Zod schemas. A Kubb pipeline generates typed clients, React Query hooks, and Zod validators from the spec.","sidebar":"docs"},"architecture/overview":{"id":"architecture/overview","title":"System Overview","description":"Workloom is a package manager for AI workflow assets\u2014instructions, skills, hooks, MCP configs, provider settings\u2014with enterprise governance built in. Think npm + Terraform plan/apply + provider-aware renderers + trust gates.","sidebar":"docs"},"architecture/rendering-pipeline":{"id":"architecture/rendering-pipeline","title":"Rendering Pipeline","description":"The rendering pipeline transforms canonical packages into provider-specific files. It\'s the heart of Workloom\u2014where packages become Claude settings, Codex agents, and Cursor rules.","sidebar":"docs"},"cli/diff":{"id":"cli/diff","title":"wl diff","description":"Show file-level differences against desired state.","sidebar":"docs"},"cli/init":{"id":"cli/init","title":"wl init","description":"Initialize a workspace binding in the current directory.","sidebar":"docs"},"cli/pull":{"id":"cli/pull","title":"wl pull","description":"Render provider files from canonical packages.","sidebar":"docs"},"cli/restore":{"id":"cli/restore","title":"wl restore","description":"Restore Workloom-owned files to desired state.","sidebar":"docs"},"cli/status":{"id":"cli/status","title":"wl status","description":"Show workspace info and drift state summary.","sidebar":"docs"},"cli/sync":{"id":"cli/sync","title":"wl sync","description":"Apply desired state to local files and detect drift.","sidebar":"docs"},"cli/validate":{"id":"cli/validate","title":"wl validate","description":"Validate a Workloom manifest file against its schema.","sidebar":"docs"},"concepts/drift-detection":{"id":"concepts/drift-detection","title":"Drift Detection","description":"Workloom tracks every rendered file with SHA-256 content hashing and a five-state ownership model. When local files diverge from the desired state \u2014 whether by manual edits, accidental deletions, or stale versions \u2014 Workloom detects it and tells you exactly what changed.","sidebar":"docs"},"concepts/packages-and-assets":{"id":"concepts/packages-and-assets","title":"Packages & Assets","description":"A canonical package is the source of truth for your AI configuration. Let\'s understand how they work.","sidebar":"docs"},"concepts/providers":{"id":"concepts/providers","title":"Providers","description":"Workloom models AI tool providers explicitly because they\'re fundamentally different. A one-size-fits-all approach would compromise trust, privacy, and usability.","sidebar":"docs"},"concepts/trust-and-privacy":{"id":"concepts/trust-and-privacy","title":"Trust & Privacy","description":"Workloom is built for organizations that take AI agent governance seriously. Every asset is classified by risk level, and trust gates enforce approval requirements before anything dangerous touches disk. Privacy isn\'t an afterthought \u2014 it\'s enforced at the schema layer.","sidebar":"docs"},"concepts/workspaces-and-targets":{"id":"concepts/workspaces-and-targets","title":"Workspaces & Targets","description":"A workspace is a desired-state declaration for a repository. It says \\"this repo should have these packages, rendered for these providers, with these policies.\\"","sidebar":"docs"},"contributing":{"id":"contributing","title":"Contributing","description":"We welcome contributions! Whether you\'re fixing a bug, adding a feature, improving documentation, or building a new provider renderer, this guide will help you get set up.","sidebar":"docs"},"getting-started/first-workspace":{"id":"getting-started/first-workspace","title":"Your First Workspace","description":"Let\'s create a workspace manifest from scratch and understand its structure.","sidebar":"docs"},"getting-started/installation":{"id":"getting-started/installation","title":"Installation","description":"Get Workloom up and running in minutes.","sidebar":"docs"},"getting-started/quick-start":{"id":"getting-started/quick-start","title":"Quick Start","description":"Let\'s run through the basics and see Workloom in action.","sidebar":"docs"},"guides/ci-cd":{"id":"guides/ci-cd","title":"CI/CD Integration","description":"Use Workloom in your CI/CD pipeline to detect and prevent AI configuration drift. The wl sync --check command is designed for CI\u2014it exits with status codes that integrate cleanly with build systems.","sidebar":"docs"},"guides/claude-setup":{"id":"guides/claude-setup","title":"Setting Up Claude","description":"Workloom brings all your Claude Code configuration under one roof. Instead of managing .claude/settings.json, CLAUDE.md, skills, hooks, and agents across dozens of repos, Workloom renders them from canonical packages\u2014keeping everything in sync, version-controlled, and auditable.","sidebar":"docs"},"guides/codex-setup":{"id":"guides/codex-setup","title":"Setting Up Codex","description":"Workloom manages Codex configuration files, agent definitions, and sandbox policies from canonical packages. The unique challenge with Codex: AGENTS.md is nestable and mergeable across package boundaries, and Workloom handles multi-package merging automatically with deterministic ordering.","sidebar":"docs"},"guides/environment-config":{"id":"guides/environment-config","title":"Environment Configuration","description":"Workloom uses two shared packages to provide type-safe, validated environment variables across the monorepo: @workloom/config for loading and @workloom/environment for the variable registry.","sidebar":"docs"},"guides/monorepo":{"id":"guides/monorepo","title":"Monorepo Configuration","description":"Workloom handles monorepos natively through multi-target workspaces. Each target (root, app, service, etc.) gets its own set of providers, packages, and rendered files. Targets resolve independently with no cross-target interference.","sidebar":"docs"},"guides/role-providers":{"id":"guides/role-providers","title":"Role Providers","description":"Workloom uses a plugin-based role resolution system. Multiple providers can resolve roles from external systems (IdPs, databases, LDAP), and results are merged to produce a single internal role per user.","sidebar":"docs"},"intro":{"id":"intro","title":"Introduction","description":"The package manager for AI agent configuration.","sidebar":"docs"}}}}')}}]);